{"expression": "// Check brand filter
const brandFilter = document.querySelectorAll('[role="combobox"]')[2];
const options = brandFilter ? [...brandFilter.querySelectorAll('[role="option"], li, option')].map(o => o.textContent.trim()).filter(Boolean) : [];
